// Using predefined macros correctly
#include <stdio.h>

void log_info() {
    printf("File: %s, Line: %d\n", __FILE__, __LINE__);  // Compliant
    printf("Compiled on %s at %s\n", __DATE__, __TIME__);   // Compliant
}

// Define custom macros with different names
#define MY_DEBUG_FILE "debug.log"    // Compliant
#define MY_VERSION "1.0.0"          // Compliant

// Conditional compilation using predefined macros
#ifdef __cplusplus
extern "C" {
#endif

void my_function() {
    // Use predefined macros without modification
    if (__LINE__ > 10) {  // Compliant
        // do something
    }
}

#ifdef __cplusplus
}
#endif
